// Reads the app's barometer config (roles + geography), counts postings per
// role via JSearch (aggregates Google for Jobs: LinkedIn/Indeed/Glassdoor/...),
// then POSTs one generalized barometer point to the app.
//
// IMPORTANT — this is a RELATIVE INDEX, not a true total. JSearch has no clean
// 'total openings' field, so we use a FIXED METHOD (same query, same page depth)
// every month; the app turns that into an index (base 100), which is comparable
// month-to-month even though the raw number is a proxy. Keep the method fixed.
//
// Requires: RAPIDAPI_JSEARCH_KEY (rapidapi.com → JSearch). Set KIST_URL to your
// app (default http://127.0.0.1:8321). n8n must be able to reach it.
const KIST = $env.KIST_URL || 'http://127.0.0.1:8321';
const KEY = $env.RAPIDAPI_JSEARCH_KEY;
const PAGES = 3; // fixed depth — DO NOT change between months (breaks comparability)

const cfg = await this.helpers.httpRequest({ url: `${KIST}/api/market-barometer`, json: true });
const roles = cfg.roles || [];
const geo = (cfg.geo || []).join(', ') || 'Remote';

const counts = {};
for (const r of roles) {
  const q = `${r.query || r.label} in ${geo}`;
  let n = 0;
  for (let p = 1; p <= PAGES; p++) {
    const resp = await this.helpers.httpRequest({
      url: 'https://jsearch.p.rapidapi.com/search',
      qs: { query: q, page: String(p), num_pages: '1' },
      headers: { 'X-RapidAPI-Key': KEY, 'X-RapidAPI-Host': 'jsearch.p.rapidapi.com' },
      json: true,
    });
    n += (resp.data || []).length;
  }
  counts[r.key] = n;
}

const month = new Date().toISOString().slice(0, 7);
return [{ json: {
  month, counts,
  sources: `JSearch/Google-for-Jobs (${PAGES} pages)`,
  geo, as_of: new Date().toISOString().slice(0, 10),
} }];
